using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // --- CalculateTotal: inline cases with [DataRow] ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "No tax")]
    [DataRow(10.00, 2, 0.1, 22.00, DisplayName = "10% tax, qty 2")]
    [DataRow(0.00, 5, 0.2, 0.00, DisplayName = "Zero price")]
    [DataRow(10.00, 0, 0.1, 0.00, DisplayName = "Zero quantity")]
    [DataRow(9.99, 3, 0.0825, 32.4452250, DisplayName = "Fractional tax rate")]
    [DataRow(1000.00, 100, 1.0, 200000.00, DisplayName = "Max tax rate (100%)")]
    public void CalculateTotal_ValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: boundary/error cases with DynamicData ---

    [TestMethod]
    [DynamicData(nameof(CalculateTotal_InvalidInputData))]
    public void CalculateTotal_InvalidInputs_ThrowsArgumentOutOfRange(
        decimal unitPrice, int quantity, decimal taxRate, string expectedParamName)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));

        Assert.AreEqual(expectedParamName, ex.ParamName);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, string expectedParamName)>
        CalculateTotal_InvalidInputData =>
    [
        (-1m,  1, 0.1m, "unitPrice"),
        (10m, -1, 0.1m, "quantity"),
        (10m,  1, -0.1m, "taxRate"),
        (10m,  1, 1.1m, "taxRate"),
    ];

    // --- ApplyDiscount: inline cases with [DataRow] ---

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% off")]
    [DataRow(200.00, 25.0, 150.00, DisplayName = "25% off")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "100% off (free)")]
    [DataRow(49.99, 50.0, 24.995, DisplayName = "Fractional result")]
    public void ApplyDiscount_ValidInputs_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Negative discount")]
    [DataRow(100.1, DisplayName = "Discount over 100%")]
    public void ApplyDiscount_InvalidPercent_ThrowsArgumentOutOfRange(double discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    // --- FormatPrice ---

    [TestMethod]
    [DataRow(9.99, "$", "$9.99", DisplayName = "Default symbol")]
    [DataRow(1234.50, "€", "€1234.50", DisplayName = "Euro symbol")]
    [DataRow(0.00, "$", "$0.00", DisplayName = "Zero price")]
    [DataRow(7.1, "£", "£7.10", DisplayName = "Pads to 2 decimals")]
    public void FormatPrice_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

